}", "CreatedBy" : "e19242b2ece511f089acceb366d738ca", "CreatedOn" : "2026-03-26T21:40:21.502Z", "Name" : "Glencore - Completed List Color", "SID" : "ZglEbwJhpxmvvv", "StyleName" : "fs-list-dot-gc-completed", "TableClass" : "NamedStyle", "UpdatedBy" : "e19242b2ece511f089acceb366d738ca", "UpdatedOn" : "2026-03-26T21:47:03.358Z", "Version" : 9, "id" : "4a64dcd5295c11f1b6de6a6cbd357f46" }

{ "Active" : true, "Application" : "0a01010a40cc1dde8140cc9df97c0000", "CreatedBy" : "e19242b2ece511f089acceb366d738ca", "CreatedOn" : "2026-03-26T21:33:12.894Z", "Description" : "Glencore customised collection of functions to assist with the Work Table + extended tables. ", "Name" : "GlencoreWorkServerUtil", "SID" : "6Vym3g8hbkoGg4", "Script" : "(function(undefined) {
 let GlencoreWorkServerUtil = function() {
 return this;
 };

 let log = Logger("GlencoreWorkServerUtil");

 /**
 * Gets any field styles for the Number field based on various factors of the current record
 *
 * @param {Table record} currentRec - The current record for the styling.
 *
 * @returns {Object} stylingObj - The object that holds the styling required.
 *
 */
 GlencoreWorkServerUtil.getNumberFieldStyle = function(currentRec) {

 let classes = [];

 // HR Cases
 if (currentRec.getTableName() == "HRCase") {
 // If it's Completed, we use the Green Status Dot
 if(currentRec.WorkflowStatus() == "completed"){
 classes.push("fs-list-dot-gc-completed");
 } else 
 // Same if it's closed
 if(currentRec.WorkflowStatus() == "closed"){
 classes.push("fs-list-dot-gc-completed");
 } else
 // Orange if it's New
 if(currentRec.WorkflowStatus() == "new"){
 classes.push("fs-list-dot-gc-new");
 } else
 // Red if it's WIP
 if(currentRec.WorkflowStatus() == "work_in_progress"){
 classes.push("fs-list-dot-gc-wip");
 } else
 // Blue if we're awaiting
 if(currentRec.WorkflowStatus().includes("awaiting")){
 classes.push("fs-list-dot-gc-awaiting");
 }

 }

 //If it's an incident, we style based on if it's a major incident or children of one.
 if (currentRec.getTableName() == "Incident") {

 //If it's major, make the text bold.
 if (currentRec.MajorIncident()) {
 classes.push("fs-font-bold");
 }

 //If it's a child of a major incident, make the number italics.
 if (currentRec.RelatedIncident()) {
 classes.push("fs-font-italic");
 }
 }

 if (currentRec.ReviewRequired()) {
 classes.push("fs-list-dot-info");
 }

 return classes;
 };

 // Standard 'require' vs 'include' type construct
 if (typeof module !== "undefined" && module.exports) {
 module.exports = GlencoreWorkServerUtil;
 }
 return GlencoreWorkServerUtil;

})();
