{ "BaseStyle" : "7f000001722b130181722ba537be02ca", "CSS" : "/* 1.11 Mods */
/* Remove UI Toggle for Admins */
[cssclass="toggle-enhanced-ui"] {
 display: none !important;
}

/* Fix Email Client Toolbar Overflow */
.e-rte-toolbar {
 overflow-x: scroll;
}

/* End 1.11 Mods */

// Remove SOFI Shopping Cart Icons from Search Results
.sofi-record__list__item--related-catalogue-item .sofi-related__label:before {
 display: none !important;
}

.sofi-related__exerpt:after {
 display: none !important;
}

/*Helps with the introductory text that is typically ontop of the hero image. */
.portal-search__welcome, .portal-search__welcome-question, .suggested_searches_label{
 color: #FFFFFF;
 text-shadow: 2px 2px 2px #000000;
}
/* Suggested Search Options for Sofi */
.suggested_searches {
 color: #FFFFFF !important;
 text-shadow: 1px 1px 5px #000000 !important;
 text-decoration: underline;
 text-decoration-thickness: 3px;
 display: none;
}

/* Suggested Searches Entries */
.suggested_searches_entry {
 color: #FFFFFF !important;
 text-shadow: 1px 1px 5px #000000 !important;
 text-decoration: underline;
 text-decoration-thickness: 3px;
}

/* Can be used to invert the colors of the Logo - helpful for logos that are white */
.login-header img {
 /* filter: invert(1); */
}

/* Gives the Catalog and Category Icons a bit of extra margin */
.sb-portal-catalog__category-img-wrapper {
 margin-bottom: 1em !important;
}

/*Determines where the hero/background image is positioned on the homepage*/
.sb-portal::before {
 background-size: cover !important;
 background-position: right top !important;
}

.portal-list__block_wrapper {
 background-color: #F4F1F0;
}

.portal-list__secondary-button {
 color: black !important;
 border-color: black !important;
}

.generic-link__wrapper[_ngcontent-pag-c457]:after {
 background-color: var(--primary) !important;
}

.toggle-carousel[_ngcontent-mas-c376] > .toggle-value.is-active[_ngcontent-mas-c376] {
 color: black !important;
}

.toggle-carousel[_ngcontent-mas-c376] > .toggle-value.is-active[_ngcontent-mas-c376] {
 color: black !important;
}


